return items.map(item => {
  const fs = item.json.output?.foundSocials || {};

  const cleanedSocials = Object.fromEntries(
    Object.entries(fs)
      .filter(([_, arr]) => Array.isArray(arr) && arr.length > 0)
      .map(([key, arr]) =>
        arr.length === 1 ? [key, arr[0]] : [key, arr]
      )
  );

  // Build unified object
  const finalOutput = {
    socials: cleanedSocials,
    score: item.json.output?.score ?? null,
    label: item.json.output?.label ?? null
  };

  // ❗ Return ONLY finalOutput as each item
  return { json: finalOutput };
});

let parts = [];
const input = $input.first().json;

// Inject homepage URL from Webhook
input.team_page_url = $('Webhook').first().json.body.homepage_url || "";

// Normalize fields
const city = Array.isArray(input.city) ? input.city[0] : input.city;
const state = Array.isArray(input.state) ? input.state[0] : input.state;
const zip = Array.isArray(input.zip_code) ? input.zip_code[0] : input.zip_code;

// --------------------------------------------------
// CLEAN HOMEPAGE URL → DOMAIN ROOT
// --------------------------------------------------
let cleanedDomain = "";

if (input.team_page_url && input.team_page_url.toUpperCase() !== "NA") {
	try {
		let url = input.team_page_url.trim();

		// Remove http, https, www
		url = url.replace(/^https?:\/\//i, "").replace(/^www\./i, "");

		// Get part before slash
		url = url.split("/")[0];

		// Strip common TLDs
		url = url.replace(/\.(com|net|org|team|co|io|us|info|realtor|realestate)$/i, "");

		if (url.toUpperCase() !== "NA" && url !== "") {
			cleanedDomain = url;
		}
	} catch (err) {
		cleanedDomain = "";
	}
}

// --------------------------------------------------
// PRIORITY LOGIC WITH NA FALLBACK
// --------------------------------------------------
if (input.team_name && input.team_name.trim().toUpperCase() !== "NA") {
	parts.push(input.team_name.trim());
} else if (cleanedDomain) {
	parts.push(cleanedDomain);
} else if (
	input.first_name && input.last_name && input.brokerage &&
	input.first_name.toUpperCase() !== "NA" &&
	input.last_name.toUpperCase() !== "NA" &&
	input.brokerage.toUpperCase() !== "NA"
) {
	parts.push(`${input.first_name} ${input.last_name} ${input.brokerage}`);
} else if (
	input.first_name && input.last_name &&
	input.first_name.toUpperCase() !== "NA" &&
	input.last_name.toUpperCase() !== "NA"
) {
	parts.push(`${input.first_name} ${input.last_name}`);
}

// --------------------------------------------------
// Add real-estate relevance keywords
// --------------------------------------------------
parts.push(`"real estate" OR realtor OR "real estate team"`);

// --------------------------------------------------
// Add location info if not NA
// --------------------------------------------------
if (city && city.toUpperCase() !== "NA") parts.push(city);
if (state && state.toUpperCase() !== "NA") parts.push(state);
if (zip && zip.toUpperCase() !== "NA") parts.push(zip);

// --------------------------------------------------
// Add social filters
// --------------------------------------------------
parts.push(
	"site:facebook.com OR site:instagram.com OR site:linkedin.com OR site:youtube.com OR site:tiktok.com"
);

// --------------------------------------------------
// Final query
// --------------------------------------------------
let q = parts.join(" ").replace(/\s+/g, " ").trim();

return [
	{
		json: {
			q,
			gl: "us",
			num: 15
		}
	}
];
